'use client';

import { useState, useEffect, Suspense } from 'react';
import { OSProvider } from '../context/OSContext';
import { Desktop } from '../components/OS/Desktop';
import { PortfolioApp } from '../components/Apps/PortfolioApp';
import { AIDashboardApp } from '../components/Apps/AIDashboardApp';
import { MarketingDeskApp } from '../components/Apps/MarketingDeskApp';
import { WorkspaceApp } from '../components/Apps/WorkspaceApp';
import { AdminApp } from '../components/Apps/AdminApp';
import { ClientCentreApp } from '../components/Apps/ClientCentreApp';

function HomeContent() {
  const [standaloneApp, setStandaloneApp] = useState<string | null>(null);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const app = params.get('app');
    if (app) {
      setTimeout(() => {
        setStandaloneApp(app);
      }, 0);
    }
  }, []);

  useEffect(() => {
    if (!standaloneApp) return;
    const handleUnload = () => {
      if (window.opener && !window.opener.closed) {
        window.opener.postMessage({ type: 'APP_CLOSED', appId: standaloneApp }, '*');
      }
    };
    window.addEventListener('beforeunload', handleUnload);
    return () => window.removeEventListener('beforeunload', handleUnload);
  }, [standaloneApp]);

  if (standaloneApp) {
    return (
      <main className="relative w-screen h-screen overflow-hidden bg-[#050508] text-slate-100 flex flex-col">
        {standaloneApp === 'portfolio' && <PortfolioApp />}
        {standaloneApp === 'ai_dashboard' && <AIDashboardApp />}
        {standaloneApp === 'marketing_desk' && <MarketingDeskApp />}
        {standaloneApp === 'workspace' && <WorkspaceApp />}
        {standaloneApp === 'client_centre' && <ClientCentreApp />}
        {standaloneApp === 'admin' && <AdminApp />}
      </main>
    );
  }

  return (
    <main className="relative w-screen h-screen overflow-hidden flex flex-col">
      <Desktop />
    </main>
  );
}

export default function Home() {
  return (
    <OSProvider>
      <Suspense fallback={<div className="w-screen h-screen bg-[#030303] flex items-center justify-center text-white font-semibold">Loading OS...</div>}>
        <HomeContent />
      </Suspense>
    </OSProvider>
  );
}
